### 3. 模板语法
```html
<div *ngFor="let item of items; let i = index">
  {{ i }}: {{ item.name }}
</div>

<div [ngSwitch]="status">
  <span *ngSwitchCase="'loading'">Loading...</span>
  <span *ngSwitchCase="'error'">Error!</span>
  <span *ngSwitchDefault>Default</span>
</div>
```

### 4. 管道 (Pipes)
```typescript
// 内置管道
{{ value | uppercase }}
{{ value | date:'short' }}
{{ value | currency:'USD' }}
{{ items | filter:'term' }}
{{ value | async }}
```

### 5. 表单处理
```typescript
// 模板驱动表单
<form #myForm="ngForm" (ngSubmit)="onSubmit(myForm)">
  <input [(ngModel)]="model.name" name="name" required>
  <button type="submit" [disabled]="!myForm.valid">Submit</button>
</form>

// 响应式表单
form = new FormGroup({
  name: new FormControl('', [Validators.required, Validators.minLength(2)]),
  email: new FormControl('', [Validators.email]),
  age: new FormControl(18, [Validators.min(0), Validators.max(150)])
});
```

### 6. HTTP 请求
```typescript
// 使用 HttpClient
@Injectable({ providedIn: 'root' })
export class DataService {
  constructor(private http: HttpClient) {}

  getData() {
    return this.http.get<Data[]>('/api/data');
  }

  postData(data: Data) {
    return this.http.post('/api/data', data);
  }
}
```

### 7. 路由
```typescript
// 路由配置
const routes: Routes = [
  { path: '', component: HomeComponent },
  { path: 'about', component: AboutComponent },
  { 
    path: 'user/:id', 
    component: UserComponent,
    canActivate: [AuthGuard]
  },
  { path: '**', component: NotFoundComponent }
];

